UPDATE decision_nodes SET data = '{"type":"info","module":1,"title":"Wet Gangrene Management","body":"**Wet gangrene = infection + tissue necrosis = SURGICAL EMERGENCY**\n\n**Differentiate from dry gangrene:**\n| Feature | Dry Gangrene | Wet Gangrene |\n|---------|--------------|---------------|\n| Appearance | Desiccated, mummified | Edematous, purulent |\n| Infection | None | Present |\n| Urgency | Can observe | URGENT surgery |\n| Treatment | May autoamputate | Surgical amputation |\n\n**Immediate management:**\n1. **Sepsis bundle** - fluids, antibiotics, lactate monitoring\n2. **Broad-spectrum antibiotics** (same as nec fasc regimen)\n3. **Emergent surgical consultation for amputation**\n4. **Glucose control** - target 140-180 mg/dL\n5. **DVT prophylaxis**\n\n**Surgical decision:**\n- Guillotine amputation if critically ill (definitive closure later)\n- Level determined by tissue viability and perfusion\n- TcPO2 >25 mmHg at proposed level suggests healing [3][5]","citation":[3,5],"next":"dfw-dispo-admit-icu","treatment":{"firstLine":{"drug":"Vancomycin + Piperacillin-tazobactam","dose":"Vanc 15-20 mg/kg, Pip-tazo 4.5g","route":"IV","frequency":"Vanc q8-12h, Pip-tazo q6h","duration":"Until amputation/source control","notes":"Add Clindamycin if concern for Group A Strep or toxin-mediated illness.","confidence":"critical"},"monitoring":"Serial exams, lactate q4-6h, glucose control target 140-180 mg/dL"},"images":[{"src":"images/diabetic-foot-wounds/dfu-wet-gangrene.jpg","alt":"Wet gangrene of the foot with dark necrotic tissue and surrounding cellulitis","caption":"Wet gangrene: purulent, foul-smelling necrosis with surrounding cellulitis. Wet gangrene + sepsis = emergent surgical amputation. (CC, Wikimedia Commons)"}],"summary":"Wet Gangrene Management — review key clinical information before proceeding"}'::jsonb
