UPDATE decision_nodes SET data = '{"type":"info","module":1,"title":"Wound Examination","body":"**Systematic wound assessment:**\n\n**Location (affects healing):**\n- Forefoot: most common, better prognosis\n- Midfoot: Charcot zone, higher amputation risk\n- Hindfoot/heel: worst prognosis, difficult offloading\n\n**Size:**\n- Measure after debridement\n- Length x width in cm\n- >2 cm² is independent risk factor for osteomyelitis\n\n**Depth (use blunt probe):**\n- Superficial: epidermis/dermis only\n- Deep: tendon, joint capsule, fascia\n- Bone: visible or palpable\n\n**Tissue type:**\n- Granulating (healthy red tissue)\n- Slough (yellow fibrinous tissue)\n- Eschar (black necrotic tissue)\n- Exposed structures (tendon, bone)\n\n**Surrounding skin:**\n- Erythema extent (measure from wound edge)\n- Warmth, induration\n- Maceration\n- Callus (neuropathic pressure point)\n\n**Exudate:**\n- None, serous, serosanguinous, purulent\n- Amount: minimal, moderate, copious\n\n**Neuropathy assessment:**\n- 10g monofilament test (loss = neuropathy)\n- 128 Hz tuning fork (vibration sense)\n- Ankle reflexes [1][7]","citation":[1,7],"next":"dfw-classification","images":[{"src":"images/diabetic-foot-wounds/diabetic-foot-ulcer.jpg","alt":"Diabetic foot ulcer with surrounding callus and erythema","caption":"Diabetic foot ulcer: neuropathic ulcers typically at plantar/pressure points with callus rim — probe-to-bone test if wound depth unclear. (CC BY-SA, Wikimedia Commons)"},{"src":"images/diabetic-foot-wounds/dfu-typical.jpg","alt":"Diabetic foot ulcer on the plantar surface with surrounding callus","caption":"Typical neuropathic plantar DFU — punched-out, painless, surrounded by hyperkeratotic callus. (CC, Wikimedia Commons)"},{"src":"images/diabetic-foot-wounds/dfu-neuropathic-heel.jpg","alt":"Neuropathic heel ulcer in a diabetic patient","caption":"Neuropathic heel ulcer — high-pressure point, often missed until full-thickness. Always probe to bone. (CC, Wikimedia Commons)"}],"calculatorLinks":[{"id":"dfw-wagner-pedis","label":"Wagner/PEDIS Classification"}],"summary":"Wound Examination — review key clinical information before proceeding","skippable":true}'::jsonb
