-- Node: dfw-classification (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":1,"title":"Wound Classification Systems","body":"**Wagner Classification (0-5):**\n| Grade | Description |\n|-------|-------------|\n| 0 | Pre-ulcerative (intact skin, deformity, cellulitis) |\n| 1 | Superficial ulcer (epidermis/dermis only) |\n| 2 | Deep ulcer (tendon, joint, fascia - no abscess/osteo) |\n| 3 | Deep ulcer WITH abscess, osteomyelitis, or tendonitis |\n| 4 | Partial gangrene (toes or forefoot) |\n| 5 | Extensive gangrene (entire foot) |\n\n**University of Texas (UT) System:**\n- Grade 0-3 (depth) x Stage A-D (complications)\n- Stage A: no infection, no ischemia\n- Stage B: infection present\n- Stage C: ischemia present\n- Stage D: BOTH infection AND ischemia (worst prognosis)\n\n**SINBAD Score (0-6 points):**\n| Factor | 0 points | 1 point |\n|--------|----------|--------|\n| Site | Forefoot | Midfoot/hindfoot |\n| Ischemia | Pulses present | PAD signs |\n| Neuropathy | Sensation intact | Loss of sensation |\n| Bacterial infection | None | Present |\n| Area | <1 cm² | ≥1 cm² |\n| Depth | Superficial | Deep |\n\nScore <3: 60% heal at 12 weeks, 0.7% major amputation\nScore ≥3: 35% heal at 12 weeks, 2.7% major amputation [7][8]","citation":[7,8],"next":"dfw-infection-intro","images":[{"src":"images/diabetic-foot-wounds/dfu-wagner1-debridement.jpg","alt":"Wagner Grade 1 diabetic foot ulcer before and after sharp debridement","caption":"Wagner Grade 1 ulcer (superficial, no infection) before and after sharp debridement of necrotic tissue and undermined edges. (Dayya 2022, CC BY 4.0, Wikimedia Commons)"},{"src":"images/diabetic-foot-wounds/dfu-toe.png","alt":"Diabetic toe ulcer demonstrating depth and surrounding tissue compromise","caption":"Diabetic toe ulcer — small surface area can mask deep tissue extension; always probe and consider Wagner staging. (CC, Wikimedia Commons)"}],"calculatorLinks":[{"id":"dfw-wagner-pedis","label":"Wagner/PEDIS Classification"}],"summary":"Wagner classification: grade 0-5 determines management — grade 3+ often requires surgery","skippable":true}'::jsonb
WHERE id = 'dfw-classification' AND tree_id = 'diabetic-foot-wounds';

-- Node: dfw-charcot-intro (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":5,"title":"Charcot Foot: A Commonly Missed Diagnosis","body":"**Charcot neuroarthropathy (CN) is a MEDICAL EMERGENCY that can lead to irreversible deformity.**\n\n**Prevalence:** Up to 13% of diabetics with neuropathy\n\n**CRITICAL FACT: 25% of acute Charcot is MISDIAGNOSED** (as cellulitis, gout, DVT, sprain)\n\n**Average delay to diagnosis: 7 months**\n\n**Risk factors:**\n- Diabetes with peripheral neuropathy (most common)\n- Long-standing diabetes (>10 years)\n- Tight glycemic control (relative)\n- Prior foot surgery or trauma\n- Obesity\n- Renal transplant patients\n\n**Pathophysiology:**\n- Autonomic neuropathy → increased blood flow → bone resorption\n- Sensory neuropathy → continued weight-bearing despite injury\n- Motor neuropathy → abnormal biomechanics\n- Result: Progressive bone destruction, fragmentation, deformity\n\n**Most common location:** Midfoot (tarsometatarsal joints - Lisfranc area) [14][15]","citation":[14,15],"next":"dfw-charcot-presentation","images":[{"src":"images/diabetic-foot-wounds/dfu-charcot.jpg","alt":"Chronic Charcot foot deformity with collapsed midfoot arch and rocker-bottom shape","caption":"Chronic Charcot foot deformity: collapsed Lisfranc joints producing the classic rocker-bottom foot. Often misdiagnosed as cellulitis early in the active phase. (CC BY-SA, Wikimedia Commons)"}],"summary":"Charcot Foot: A Commonly Missed Diagnosis — review key clinical information before proceeding"}'::jsonb
WHERE id = 'dfw-charcot-intro' AND tree_id = 'diabetic-foot-wounds';

-- Node: dfw-charcot-presentation (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":5,"title":"Acute Charcot: Clinical Presentation","body":"**Classic triad of acute Charcot:**\n1. **Unilateral swollen foot/ankle**\n2. **Warmth** (2-8°C difference vs. contralateral)\n3. **Erythema**\n\n**Key distinguishing features from infection:**\n| Feature | Acute Charcot | Osteomyelitis/Cellulitis |\n|---------|---------------|-------------------------|\n| Open wound | Usually ABSENT | Usually PRESENT |\n| Fever | Absent | May be present |\n| WBC | Normal | Often elevated |\n| ESR/CRP | Mildly elevated | Significantly elevated |\n| Pain | Minimal (neuropathy) | Variable |\n| Pulses | Often bounding | Variable |\n\n**Red flags for Charcot:**\n- Diabetic >40 years with neuropathy\n- Red, hot, swollen foot WITHOUT open wound\n- Minimal or no pain despite appearance\n- History of minor or unrecalled trauma\n- Normal systemic vitals and labs\n- Patient walking on affected foot without complaint\n\n**Diagnostic approach:**\n1. Compare temperature to contralateral foot\n2. Weight-bearing X-rays (may be normal early)\n3. MRI if X-ray normal but high clinical suspicion\n4. Labs: CBC, BMP, ESR, CRP (to help r/o infection) [14][15]","citation":[14,15],"next":"dfw-charcot-staging","images":[{"src":"images/diabetic-foot-wounds/dfu-charcot-active.jpg","alt":"Active stage Charcot foot — red, hot, swollen midfoot without open wound","caption":"Active (Eichenholtz Stage 0/1) Charcot — red, hot, swollen foot without an open wound. 2-8°C warmer than contralateral. Often misread as cellulitis. (CC, Wikimedia Commons)"}],"summary":"Acute Charcot: Clinical Presentation — review key clinical information before proceeding"}'::jsonb
WHERE id = 'dfw-charcot-presentation' AND tree_id = 'diabetic-foot-wounds';

